// Fold:
//   select (select C, X, false), A, (select C, B, D) -> select C, (select X, A, B), D
//   select (select C, X, false), (select C, B, D), A -> select C, (select X, B, A), D
//   select (select C, true, X), A, (select C, B, D) -> select C, A, (select X, A, D)
//   select (select C, true, X), (select C, B, D), A -> select C, B, (select X, D, A)
static Instruction *foldSelectWithAndOrCond(SelectInst &SI,
                                            InstCombiner::BuilderTy &Builder) {
  Value *CondVal = SI.getCondition();
  Value *TrueVal = SI.getTrueValue();
  Value *FalseVal = SI.getFalseValue();

  // The outer select condition must be a select of boolean type.
  auto *CondSel = dyn_cast<SelectInst>(CondVal);
  if (!CondSel || !CondSel->getType()->isIntOrIntVectorTy(1))
    return nullptr;

  Value *C = CondSel->getCondition();
  Value *X = CondSel->getTrueValue();
  Value *CondFalse = CondSel->getFalseValue();

  bool IsAnd;
  if (match(CondFalse, m_Zero()) && !match(X, m_One()))
    IsAnd = true;  // select C, X, false  ->  C && X
  else if (match(X, m_One()) && !match(CondFalse, m_Zero()))
    IsAnd = false; // select C, true, X  ->  C || X
  else
    return nullptr;

  // Check if TrueVal or FalseVal is also a select with the same condition C.
  auto TryMatch = [&](Value *&Val, Value *&OtherVal, bool ValIsTrue) -> Instruction * {
    auto *Sel = dyn_cast<SelectInst>(Val);
    if (!Sel || Sel->getCondition() != C)
      return nullptr;

    // Both inner selects should have one use.
    if (!CondSel->hasOneUse() || !Sel->hasOneUse())
      return nullptr;

    Value *B = Sel->getTrueValue();
    Value *D = Sel->getFalseValue();
    Value *A = OtherVal;

    if (IsAnd) {
      // select (select C, X, false), A, (select C, B, D) -> select C, (select X, A, B), D
      // select (select C, X, false), (select C, B, D), A -> select C, (select X, B, A), D
      Value *InnerSel = Builder.CreateSelect(X, A, B);
      return SelectInst::Create(C, InnerSel, D);
    } else {
      // select (select C, true, X), A, (select C, B, D) -> select C, A, (select X, A, D)
      // select (select C, true, X), (select C, B, D), A -> select C, B, (select X, D, A)
      Value *InnerSel = Builder.CreateSelect(X, A, D);
      return SelectInst::Create(C, A, InnerSel);
    }
  };

  if (Instruction *R = TryMatch(FalseVal, TrueVal, false))
    return R;
  if (Instruction *R = TryMatch(TrueVal, FalseVal, true))
    return R;

  return nullptr;
}

