+
+  Value *C = CondSel->getCondition();
+  Value *X = CondSel->getTrueValue();
+  Value *CondFalse = CondSel->getFalseValue();
+
+  bool IsAnd;
+  if (match(CondFalse, m_Zero()) && !match(X, m_One()))
+    IsAnd = true;  // select C, X, false  ->  C && X
+  else if (match(X, m_One()) && !match(CondFalse, m_Zero()))
+    IsAnd = false; // select C, true, X  ->  C || X
+  else
+    return nullptr;
+
+  // Check if TrueVal or FalseVal is also a select with the same condition C.
+  auto TryMatch = [&](Value *&Val, Value *&OtherVal, bool ValIsTrue) -> Instruction * {
+    auto *Sel = dyn_cast<SelectInst>(Val);
+    if (!Sel || Sel->getCondition() != C)
+      return nullptr;
+
+    // Both inner selects should have one use.
+    if (!CondSel->hasOneUse() || !Sel->hasOneUse())
